<div class="container py-4"><a href="<?= url('/portal') ?>" class="btn btn-link ps-0">← Nueva consulta</a><?php if(!$order): ?><div class="alert alert-warning">No se encontró la orden con los datos proporcionados.</div><?php else: ?><div class="card mb-3"><div class="card-body"><h4>Orden <?= e($order['order_number']) ?></h4><p class="mb-1"><strong>Cliente:</strong> <?= e($order['customer']) ?></p><p class="mb-1"><strong>Equipo:</strong> <?= e($order['device_type'].' '.$order['brand'].' '.$order['model']) ?></p><p class="mb-1"><strong>Estado actual:</strong> <span class="badge bg-primary"><?= e($order['status_name']) ?></span></p><p class="mb-1"><strong>Total estimado:</strong> $<?= number_format((float)$order['estimated_total'],0,',','.') ?></p><p class="mb-0"><strong>Comentarios:</strong> <?= e((string)$order['public_notes']) ?></p></div></div><div class="card"><div class="card-body"><h6>Línea de tiempo</h6><?php foreach($history as $h): ?><div class="border-start ps-3 mb-2"><strong><?= e($h['new_status_name']) ?></strong><br><small><?= e($h['changed_at']) ?></small><div><?= e((string)$h['public_comment']) ?></div></div><?php endforeach; ?></div></div><?php endif; ?></div>
